// Extract content from API response
const response = $input.first().json;
const content = response.choices[0].message.content;
const projectName = $('Set Variables & Prompt1').first().json.project_name;
const timestamp = $('Set Variables & Prompt1').first().json.timestamp;
const verifyPrompt = $('verification prompt1').first().json.verifyprompt;

// Clean project name for filename
const cleanName = projectName.replace(/[^a-z0-9]/gi, '_').toLowerCase();

return {
  json: {
    content: content,
    project_name: projectName,
    filename: `${cleanName}_${timestamp}.txt`,
    timestamp: timestamp,
    verification_prompt: verifyPrompt
  }
};

// Parse verification response
const response = $input.first().json;
const verificationText = response.choices[0].message.content;

// Extract JSON from response (handle markdown code blocks)
let verificationResult;
try {
  const jsonMatch = verificationText.match(/\{[\s\S]*\}/);
  verificationResult = JSON.parse(jsonMatch[0]);
} catch (e) {
  verificationResult = {
    verification_passed: false,
    errors: ['Failed to parse verification response'],
    missing_sections: [],
    warnings: []
  };
}

const previousData = $('Extract Content1').first().json;

return {
  json: {
    ...previousData,
    verification: verificationResult,
    passed: verificationResult.verification_passed
  }
};
